import{Logger}from '../shared/logger.js';const AutoSave={instances: new Map(),init(selector,options={}){const form=typeof selector==='string' ? document.querySelector(selector): selector;if(!form){Logger.error('AutoSave: Form not found',{selector});return null;}const config={key: `form-draft-${form.id||Date.now()}`,delay: 2000,onSave: null,onRecover: null,showIndicator: true,storageKey: 'autosave',...options};const instance={form,config,timer: null,lastSaved: null,isDirty: false,status: 'idle'};this.bindFormEvents(instance);this.recoverData(instance);this.instances.set(form,instance);Logger.debug('AutoSave initialized',{form: form.id,key: config.key});return instance;},bindFormEvents(instance){const{form,config}=instance;form.addEventListener('input',(e)=>{instance.isDirty=true;this.updateStatus(instance,'dirty');this.scheduleSave(instance);});form.addEventListener('change',(e)=>{instance.isDirty=true;this.scheduleSave(instance);});form.addEventListener('keydown',(e)=>{if((e.ctrlKey||e.metaKey)&&e.key==='s'){e.preventDefault();this.forceSave(instance);}});form.addEventListener('submit',async(e)=>{if(instance.isDirty){await this.forceSave(instance);}});if(config.showIndicator){this.createIndicator(instance);}},scheduleSave(instance){if(instance.timer){clearTimeout(instance.timer);}instance.timer=setTimeout(()=>{this.save(instance);},instance.config.delay);},async save(instance){if(!instance.isDirty)return;this.updateStatus(instance,'saving');try{const formData=this.getFormData(instance.form);const timestamp=Date.now();this.saveToStorage(instance.config,formData,timestamp);if(instance.config.onSave){await instance.config.onSave(formData,instance);}instance.lastSaved=timestamp;instance.isDirty=false;this.updateStatus(instance,'saved');Logger.debug('AutoSave completed',{form: instance.form.id});}catch(error){this.updateStatus(instance,'error');Logger.error('AutoSave failed',{error,form: instance.form.id});}},async forceSave(instance){if(instance.timer){clearTimeout(instance.timer);instance.timer=null;}await this.save(instance);},recoverData(instance){try{const stored=this.loadFromStorage(instance.config);if(!stored)return;const{data,timestamp}=stored;Object.entries(data).forEach(([key,value])=>{const field=instance.form.querySelector(`[name="${key}"]`);if(field){field.value=value;}});instance.lastSaved=timestamp;instance.isDirty=false;if(instance.config.onRecover){instance.config.onRecover(data,timestamp);}Logger.info('AutoSave data recovered',{form: instance.form.id,timestamp});}catch(error){Logger.warn('AutoSave recovery failed',{error});}},getFormData(form){const formData=new FormData(form);const data={};for(const [key,value] of formData.entries()){if(data[key]){if(!Array.isArray(data[key])){data[key]=[data[key]];}data[key].push(value);}else{data[key]=value;}}return data;},saveToStorage(config,data,timestamp){const storage=JSON.parse(localStorage.getItem(config.storageKey)||'{}');storage[config.key]={data,timestamp};localStorage.setItem(config.storageKey,JSON.stringify(storage));},loadFromStorage(config){const storage=JSON.parse(localStorage.getItem(config.storageKey)||'{}');return storage[config.key];},createIndicator(instance){const indicator=document.createElement('div');indicator.className='autosave-indicator';indicator.innerHTML=`<span class="autosave-status">✓ Đã lưu</span><span class="autosave-time"></span>`;indicator.style.cssText=` position: fixed;bottom: 20px;right: 80px;padding: 8px 16px;background: rgba(0,128,0,0.9);color: white;border-radius: 20px;font-size: 13px;opacity: 0;transition: opacity 0.3s ease;z-index: 9997;display: flex;gap: 8px;align-items: center;`;document.body.appendChild(indicator);instance.indicator=indicator;},updateStatus(instance,status){if(!instance.indicator)return;const statusEl=instance.indicator.querySelector('.autosave-status');const timeEl=instance.indicator.querySelector('.autosave-time');const statusMap={idle:{text: '',show: false},dirty:{text: 'Đang soạn...',show: true,color: '#999'},saving:{text: 'Đang lưu...',show: true,color: '#ff9800'},saved:{text: '✓ Đã lưu',show: true,color: '#4caf50'},error:{text: '✕ Lỗi lưu',show: true,color: '#f44336'}};const config=statusMap[status];if(statusEl){statusEl.textContent=config.text;statusEl.style.color=config.color;}if(instance.lastSaved&&timeEl){const date=new Date(instance.lastSaved);timeEl.textContent=date.toLocaleTimeString('vi-VN',{hour: '2-digit',minute: '2-digit'});}instance.indicator.style.opacity=config.show ? '1' : '0';if(status==='saved'){setTimeout(()=>{instance.indicator.style.opacity='0';},3000);}},clear(instance){try{const storage=JSON.parse(localStorage.getItem(instance.config.storageKey)||'{}');delete storage[instance.config.key];localStorage.setItem(instance.config.storageKey,JSON.stringify(storage));instance.lastSaved=null;instance.isDirty=false;Logger.debug('AutoSave data cleared',{form: instance.form.id});}catch(error){Logger.warn('AutoSave clear failed',{error});}},getInstance(form){return this.instances.get(form);},destroy(instance){if(instance.timer){clearTimeout(instance.timer);}if(instance.indicator){instance.indicator.remove();}this.instances.delete(instance.form);Logger.debug('AutoSave destroyed',{form: instance.form.id});}};export default AutoSave;